+/**
+ * Get the completion status of a dispatch
+ */
+export function getDispatchStatus(dispatch: AgentDispatch): {
+  pending: number;
+  dispatched: number;
+  received: number;
+  errors: number;
+  total: number;
+  complete: boolean;
+} {
+  const counts = {
+    pending: 0,
+    dispatched: 0,
+    received: 0,
+    errors: 0,
+    total: dispatch.tasks.length,
+    complete: dispatch.complete,
+  };
+
+  for (const task of dispatch.tasks) {
+    switch (task.status) {
+      case "pending":
+        counts.pending++;
+        break;
+      case "dispatched":
+        counts.dispatched++;
+        break;
+      case "received":
+        counts.received++;
+        break;
+      case "error":
+        counts.errors++;
+        break;
+    }
+  }
+
+  return counts;
+}
